import React, { useEffect, useState } from "react";
import dft from "../../images/default.jpeg";
import { useNavigate } from "react-router-dom";
const Followers = () => {
  const [FollowingList, setFollowingList] = useState([]);
  const [FollowerList, setFollowerList] = useState([]);
  const navigate = useNavigate();
  useEffect(() => {
    const fetchSaves = async () => {
      const response = await fetch("http://localhost:8000/api/followShow", {
        method: "GET",
        headers: {
          "content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
      });
      const data = await response.json();
      console.log(data?.followerList, data?.followingList);
      setFollowerList(data?.followerList);
      setFollowingList(data?.followingList);
    };
    fetchSaves();
  }, []);
  return (
    <div>
      <div className="flex">
        <div className="w-[50%] flex flex-col items-center">
          <h1 className="text-xl font-bold mb-[5px] border-b">Followers</h1>
          {FollowerList?.map(({ followerId }) => {
            return (
              <div
                className="h-[55px] flex border-b cursor-pointer"
                onClick={() => {
                  navigate(`/user/${userName}`);
                }}
              >
                <img
                  src={profilePic || dft}
                  alt="ProfilePic"
                  className="h-[50px] w-[50px] rounded-3xl relative left-[5px]"
                ></img>
                <p className="flex justify-center items-center ml-[20px] text-[25px]">
                  {userName}
                </p>
              </div>
            
            );
          })}
        </div>
        <div className="w-[50%] flex flex-col items-center ">
          <h1 className="text-xl font-bold mb-[5px] border-b">Following</h1>
          {FollowingList?.map(({ followedId }) => {
            return (
             <div
                className="h-[55px] flex border-b cursor-pointer"
                onClick={() => {
                  navigate(`/user/${userName}`);
                }}
              >
                <img
                  src={profilePic || dft}
                  alt="ProfilePic"
                  className="h-[50px] w-[50px] rounded-3xl relative left-[5px]"
                ></img>
                <p className="flex justify-center items-center ml-[20px] text-[25px]">
                  {userName}
                </p>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

export default Followers;
